#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        unsigned long long xorsum = 0ULL;
        for(int i=1;i<=N;i++){
            long long a; scanf("%lld", &a);
            unsigned long long g;
            if(i%2==0) g = (unsigned long long)(a/2);
            else g = (unsigned long long)(a%2);
            xorsum ^= g;
        }
        if(xorsum) printf("CHEF\n");
        else printf("CHEFINA\n");
    }
    return 0;
}

